function renderRadar(){ $$('.platform-card').forEach((c,i)=>c.classList.toggle('active',storyData.platforms[i].name===currentRadar.name));const canvas=$('#riskRadar'),ctx=canvas.getContext('2d'),dpr=devicePixelRatio||1,rect=canvas.getBoundingClientRect(),W=Math.max(560,rect.width)*dpr,H=Math.max(560,rect.width)*dpr;canvas.width=W;canvas.height=H;ctx.clearRect(0,0,W,H);const cx=W/2,cy=H/2,R=Math.min(W,H)*.24,labels=['情绪依附','冲突回避','现实替代','退出回应'];ctx.save();ctx.translate(cx,cy);for(let ring=1;ring<=4;ring++){ctx.beginPath();for(let i=0;i<4;i++){const a=-Math.PI/2+i*Math.PI*2/4,r=R*ring/4,x=Math.cos(a)*r,y=Math.sin(a)*r;i?ctx.lineTo(x,y):ctx.moveTo(x,y)}ctx.closePath();ctx.strokeStyle='rgba(80,60,120,.13)';ctx.lineWidth=1*dpr;ctx.stroke()}for(let i=0;i<4;i++){const a=-Math.PI/2+i*Math.PI*2/4;ctx.beginPath();ctx.moveTo(0,0);ctx.lineTo(Math.cos(a)*R,Math.sin(a)*R);ctx.strokeStyle='rgba(80,60,120,.14)';ctx.stroke();ctx.fillStyle='rgba(31,27,46,.78)';ctx.font=`${14*dpr}px Microsoft YaHei`;ctx.textBaseline='middle';let x=Math.cos(a)*(R+100*dpr),y=Math.sin(a)*(R+74*dpr);ctx.textAlign=i===1?'left':i===3?'right':'center';ctx.fillText(labels[i],x,y)}const grad=ctx.createLinearGradient(-R,-R,R,R);grad.addColorStop(0,'rgba(103,167,255,.42)');grad.addColorStop(.55,'rgba(155,115,255,.46)');grad.addColorStop(1,'rgba(255,106,154,.55)');ctx.beginPath();currentRadar.risks.forEach((v,i)=>{const a=-Math.PI/2+i*Math.PI*2/4,r=R*v/100,x=Math.cos(a)*r,y=Math.sin(a)*r;i?ctx.lineTo(x,y):ctx.moveTo(x,y)});ctx.closePath();ctx.fillStyle=grad;ctx.fill();ctx.strokeStyle=currentRadar.color;ctx.lineWidth=4*dpr;ctx.stroke();currentRadar.risks.forEach((v,i)=>{const a=-Math.PI/2+i*Math.PI*2/4,r=R*v/100;ctx.beginPath();ctx.arc(Math.cos(a)*r,Math.sin(a)*r,6*dpr,0,Math.PI*2);ctx.fillStyle='#fff';ctx.fill();ctx.strokeStyle=currentRadar.color;ctx.lineWidth=3*dpr;ctx.stroke()});ctx.fillStyle='#1f1b2e';ctx.font=`900 ${32*dpr}px Microsoft YaHei`;ctx.textAlign='center';ctx.fillText(currentRadar.name,0,-6*dpr);ctx.fillStyle='rgba(31,27,46,.55)';ctx.font=`${13*dpr}px Microsoft YaHei`;ctx.fillText('四维回应雷达',0,25*dpr);ctx.restore();$('#radarCaption').innerHTML=`<strong>${currentRadar.name}</strong>｜综合指数 ${currentRadar.index}/100。EV ${currentRadar.raw.EV} / CA ${currentRadar.raw.CA} / RS ${currentRadar.raw.RS} / ER ${currentRadar.raw.ER}。${currentRadar.note}<br><span class="caption-note">${currentRadar.formula}</span>`}
