function donutPath(cx,cy,r1,r2,start,end){
  const large=end-start>Math.PI?1:0;
  const p1=[cx+Math.cos(start)*r2,cy+Math.sin(start)*r2],p2=[cx+Math.cos(end)*r2,cy+Math.sin(end)*r2],p3=[cx+Math.cos(end)*r1,cy+Math.sin(end)*r1],p4=[cx+Math.cos(start)*r1,cy+Math.sin(start)*r1];
  return `M ${p1[0]} ${p1[1]} A ${r2} ${r2} 0 ${large} 1 ${p2[0]} ${p2[1]} L ${p3[0]} ${p3[1]} A ${r1} ${r1} 0 ${large} 0 ${p4[0]} ${p4[1]} Z`;
}
function renderRiskDonut(){
  const el=document.getElementById('riskDonutChart'); if(!el) return;
  const data=industryData.risks,total=data.reduce((s,d)=>s+d.value,0),w=420,h=300,cx=145,cy=150,r1=62,r2=104;
  const svg=svgEl('svg',{viewBox:`0 0 ${w} ${h}`,role:'img','aria-label':'36组会话风险类型占比圆环图'});
  let a=-Math.PI/2; data.forEach(d=>{const end=a+d.value/total*Math.PI*2;svg.appendChild(svgEl('path',{d:donutPath(cx,cy,r1,r2,a,end),fill:d.color,opacity:.9}));a=end;});
  svg.appendChild(svgEl('text',{x:cx,y:cy-2,'text-anchor':'middle',style:'font-weight:900;font-size:36px;fill:#1f1b2e'},'36'));
  svg.appendChild(svgEl('text',{x:cx,y:cy+24,'text-anchor':'middle',class:'axis-label'},'组会话'));
  data.forEach((d,i)=>{const y=76+i*54;svg.appendChild(svgEl('rect',{x:285,y:y-15,width:18,height:18,rx:5,fill:d.color}));svg.appendChild(svgEl('text',{x:312,y:y,class:'bar-label'},`${d.name} ${d.value}组`));svg.appendChild(svgEl('text',{x:312,y:y+20,class:'axis-label'},`${(d.value/total*100).toFixed(1)}%`));});
  el.innerHTML=''; el.appendChild(svg);
  const list=document.getElementById('exitSignalChart'); if(list){list.innerHTML='<h4>退出时刻的几个信号</h4>'+industryData.exitSignals.map(x=>`<div class="signal-row"><span>${x.name}</span><i style="width:${x.value}%"></i><b>${x.value}%</b></div>`).join('');}
}
