/* === V5 dynamic scrollytelling upgrades === */
function initMotionDataChapter(){
  const motionEls = document.querySelectorAll('.motion-row, .motion-viz, .chart-card, .report-snapshot');
  const obs = new IntersectionObserver(entries=>{
    entries.forEach(entry=>{
      if(entry.isIntersecting){
        entry.target.classList.add('inview');
        if(entry.target.id==='motionData' || entry.target.classList.contains('motion-row')) startTypeLine(entry.target);
      }
    });
  },{threshold:.28, rootMargin:'0px 0px -8% 0px'});
  motionEls.forEach(el=>obs.observe(el));

  // number flip animation for visible cards
  const nums = document.querySelectorAll('.public-card b, .macro-pill b, .kpi-card b, .profile-metric b');
  const numObs = new IntersectionObserver(entries=>{
    entries.forEach(entry=>{
      if(entry.isIntersecting){ animateNumberText(entry.target); numObs.unobserve(entry.target); }
    });
  },{threshold:.6});
  nums.forEach(n=>numObs.observe(n));

  addFlowDotToPath();
}
function animateNumberText(el){
  if(el.dataset.done) return; el.dataset.done='1';
  const original = el.textContent.trim();
  const m = original.match(/^\$?([0-9]+(?:\.[0-9]+)?)(.*)$/);
  if(!m) return;
  const prefix = original.startsWith('$') ? '$' : '';
  const target = parseFloat(m[1]);
  const suffix = m[2] || '';
  const decimals = (m[1].split('.')[1]||'').length;
  const start = performance.now();
  const duration = 1100 + Math.min(900, target*1.4);
  function step(now){
    const t = Math.min(1,(now-start)/duration);
    const eased = 1 - Math.pow(1-t,3);
    const val = target*eased;
    el.textContent = prefix + val.toFixed(decimals) + suffix;
    if(t<1) requestAnimationFrame(step); else el.textContent = original;
  }
  requestAnimationFrame(step);
}
function startTypeLine(scope){
  const line = scope.querySelector ? scope.querySelector('.typed-line') : null;
  if(!line || line.dataset.typed) return;
  line.dataset.typed='1';
  const dots = scope.querySelector('.typing-dots');
  setTimeout(()=>{ if(dots) dots.style.display='none'; line.classList.add('typing-started'); }, 1300);
}
function addFlowDotToPath(){
  const svg = document.querySelector('.path-svg');
  if(!svg || svg.querySelector('.flow-dot')) return;
  const ns='http://www.w3.org/2000/svg';
  const c=document.createElementNS(ns,'circle');
  c.setAttribute('r','11'); c.setAttribute('fill','#fff'); c.setAttribute('stroke','#ff5f8f'); c.setAttribute('stroke-width','6'); c.setAttribute('class','flow-dot');
  const am=document.createElementNS(ns,'animateMotion');
  am.setAttribute('dur','5.5s'); am.setAttribute('repeatCount','indefinite');
  am.setAttribute('path','M 70 170 C 180 60, 290 60, 400 145 S 640 250, 760 130 S 890 60, 940 110');
  c.appendChild(am); svg.appendChild(c);
}
initMotionDataChapter();
(function fixDialMeters(){
  const rows=document.querySelectorAll('.risk-motion-viz');
  const obs=new IntersectionObserver(entries=>{
    entries.forEach(e=>{
      if(e.isIntersecting){
        e.target.querySelectorAll('.dial').forEach(d=>{
          const v=parseFloat(getComputedStyle(d).getPropertyValue('--v'))||0;
          const meter=d.querySelector('.meter');
          if(meter) meter.style.strokeDashoffset = String(314 - 314*v/100);
        });
      }
    });
  },{threshold:.35});
  rows.forEach(r=>obs.observe(r));
})();
